select document_comment_id, company_id, document_id, parent_comment_id, anchor_block_id, anchor_start, anchor_end, anchor_text, author_user_id, body, status, created_at, updated_at
from document_comments
where document_comment_id = #{documentCommentId,jdbcType=VARCHAR}

select document_comment_id, company_id, document_id, parent_comment_id, anchor_block_id, anchor_start, anchor_end, anchor_text, author_user_id, body, status, created_at, updated_at
from document_comments
where company_id = #{companyId,jdbcType=VARCHAR}
  and document_id = #{documentId,jdbcType=VARCHAR}
  and upper(coalesce(trim(status), '')) = 'ACTIVE'
order by created_at asc
limit #{limit,jdbcType=INTEGER}
